const task = $('Loop Tasks').item.json;
const phases = $('Load Phase Outputs').all();

const phaseSummary = phases.map(p => `${p.json.phase_id}: ${JSON.stringify(p.json.output_json).substring(0, 500)}`).join('\n\n');

const payload = {
  model: 'claude-haiku-4-5-20251001',
  messages: [
    {
      role: 'system',
      content: 'You are a NETS homework quality validator. Check the provided homework phase outputs and return a JSON object with validation results for each of 4 checks.'
    },
    {
      role: 'user',
      content: `Validate this NETS homework for: subject=${task.subject}, grade=${task.grade}, lang=${task.lang}\n\nPhase outputs:\n${phaseSummary}\n\nReturn JSON: {"language_register": {"passed": bool, "notes": str}, "framework_compliance": {"passed": bool, "notes": str}, "factual_grounding": {"passed": bool, "notes": str}, "age_appropriateness": {"passed": bool, "notes": str}}`
    }
  ],
  response_format: { type: 'json_object' },
  temperature: 0.1,
  max_tokens: 2000
};

return [{ json: { payload, task_id: task.task_id, lesson_id: task.lesson_id } }];

const response = $json;
const meta = $('Build Validation Prompt').item.json;

let results;
try {
  const content = response.content?.[0]?.text || response.choices?.[0]?.message?.content;
  results = JSON.parse(content);
} catch(e) {
  throw new Error('Validator returned invalid JSON: ' + e.message);
}

const checks = ['language_register','framework_compliance','factual_grounding','age_appropriateness'];
const rows = checks.map(check => ({
  task_id: meta.task_id,
  lesson_id: meta.lesson_id,
  phase_id: 'all',
  check_type: check,
  passed: results[check]?.passed || false,
  notes: results[check]?.notes || ''
}));

return rows.map(r => ({ json: r }));
